class SecureLogger {
  static final SecureLogger _instance = SecureLogger._internal();
  factory SecureLogger() => _instance;
  SecureLogger._internal();

  final List<String> _sensitiveKeys = [
    'password',
    'token',
    'authorization',
    'api_key',
    'apiKey',
    'secret',
    'credential',
    'auth',
    'bearer',
    'session',
    'cookie',
    'ssn',
    'credit_card',
    'creditCard',
    'cvv',
    'pin',
    'private_key',
    'privateKey',
  ];

  bool _isProduction = kReleaseMode;

  void setProductionMode(bool isProduction) {
    _isProduction = isProduction;
  }

  String _sanitize(dynamic data) {
    if (data == null) return 'null';

    if (data is String) {
      return _sanitizeString(data);
    }

    if (data is Map) {
      return _sanitizeMap(data);
    }

    if (data is List) {
      return _sanitizeList(data);
    }

    return data.toString();
  }

  String _sanitizeString(String value) {
    if (value.isEmpty) return '';
    
    if (value.length <= 4) {
      return '***';
    }
    
    return '${value.substring(0, 2)}***${value.substring(value.length - 2)}';
  }

  String _sanitizeMap(Map map) {
    final sanitized = <String, dynamic>{};
    
    map.forEach((key, value) {
      final keyStr = key.toString().toLowerCase();
      final isSensitive = _sensitiveKeys.any((sensitive) => 
        keyStr.contains(sensitive.toLowerCase())
      );

      if (isSensitive) {
        sanitized[key] = '***REDACTED***';
      } else if (value is Map) {
        sanitized[key] = _sanitizeMap(value);
      } else if (value is List) {
        sanitized[key] = _sanitizeList(value);
      } else if (value is String && value.length > 100) {
        sanitized[key] = '${value.substring(0, 50)}...[truncated]';
      } else {
        sanitized[key] = value;
      }
    });

    return jsonEncode(sanitized);
  }

  String _sanitizeList(List list) {
    final sanitized = list.map((item) {
      if (item is Map) {
        return jsonDecode(_sanitizeMap(item));
      } else if (item is List) {
        return jsonDecode(_sanitizeList(item));
      }
      return item;
    }).toList();

    return jsonEncode(sanitized);
  }

  void _log(LogLevel level, String message, {dynamic data, StackTrace? stackTrace}) {
    if (_isProduction && level == LogLevel.debug) {
      return;
    }

    final timestamp = DateTime.now().toIso8601String();
    final levelStr = level.toString().split('.').last.toUpperCase();
    final sanitizedData = data != null ? _sanitize(data) : '';
    
    final logMessage = '[$timestamp] [$levelStr] $message${sanitizedData.isNotEmpty ? '\nData: $sanitizedData' : ''}';

    if (kDebugMode) {
      debugPrint(logMessage);
      if (stackTrace != null && level == LogLevel.error) {
        debugPrint('StackTrace: $stackTrace');
      }
    }
  }

  void debug(String message, {dynamic data}) {
    _log(LogLevel.debug, message, data: data);
  }

  void info(String message, {dynamic data}) {
    _log(LogLevel.info, message, data: data);
  }

  void warning(String message, {dynamic data}) {
    _log(LogLevel.warning, message, data: data);
  }

  void error(String message, {dynamic data, StackTrace? stackTrace}) {
    _log(LogLevel.error, message, data: data, stackTrace: stackTrace);
  }
}

